import{_ as d,o as e,c as o,a5 as s}from"./chunks/framework.UejvgJX4.js";const y=JSON.parse('{"title":"接口索引（Python）","description":"","frontmatter":{"outline":2},"headers":[],"relativePath":"sdk-py/api-index.md","filePath":"sdk-py/api-index.md","lastUpdated":1784005699000}'),a={name:"sdk-py/api-index.md"};function c(r,t,n,i,l,h){return e(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="接口索引-python" tabindex="-1">接口索引（Python） <a class="header-anchor" href="#接口索引-python" aria-label="Permalink to &quot;接口索引（Python）&quot;">​</a></h1><blockquote><p><strong>读完本页你能</strong>：按 <strong>Functions / Classes / Types</strong> 分组,一眼查到每个接口的规划状态与文档落点。</p></blockquote><p>这是一张<strong>按接口名反查文档位置</strong>的索引,按 Functions / Classes / Types 分组。它与本章另两张表<strong>职责不同、互不重复</strong>:</p><ul><li><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/overview.html#interface-overview">总览的接口一览</a> —— 接口的<strong>命名与状态</strong>;</li><li><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/limits.html#coverage-matrix">边界的覆盖矩阵</a> —— 每个接口的<strong>裁剪决策与理由</strong>;</li><li><strong>本页</strong> —— Brainary 接口名 → <strong>文档落点</strong>(开发者查阅用)。</li></ul><div class="warning custom-block"><p class="custom-block-title">本章整体是「规划：镜像 Rust 的 Python 接口面」</p><p>下表状态标记统一为 🟠【规划中，未完成】；Rust 与 Python 两侧当前均尚未实现,签名为设计形态。详见 <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/overview.html">总览</a> 规划横幅。</p></div><p><strong>状态说明</strong>：brainary-agent-sdk 当前<strong>全部接口均为 🟠【规划中，未完成】</strong>——架构已规划、尚未实现；下方给出的类型、签名、字段均为<strong>已承诺的形态</strong>，供对齐讨论，非占位草案。（⚪ = 暂缓 / 不纳入，非交付接口。）</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>接口</th><th>状态</th><th>一句话</th><th>去哪页</th></tr></thead><tbody><tr><td><code>query(prompt, options)</code></td><td>🟠</td><td>一次性入口,直接是 <code>AsyncIterator[Message]</code>,<code>async for</code> 消费</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/query-and-client.html#query-一次性">两个入口</a></td></tr><tr><td><code>@tool(name, desc, schema)</code></td><td>🟠</td><td>把一个 async 函数标成工具</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/tools.html#tool-装饰器">自定义工具</a></td></tr><tr><td><code>create_sdk_mcp_server(name, version, tools)</code></td><td>🟠</td><td>一组工具打包成命名能力单元</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/tools.html#create-sdk-mcp-server">自定义工具</a></td></tr><tr><td><strong>内置工具目录</strong>（<code>read_file</code> / <code>write_file</code> / <code>edit_file</code> / <code>find_file</code> / <code>grep</code> 等）</td><td>🟠（含 schema 精化缺口）</td><td>随会话默认可用的一组内建工具；<code>bash</code> / <code>web_fetch</code> / <code>web_search</code> / <code>ask_user_question</code> / <code>agent</code>(🟠) 亦在此登记</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/builtin-tools.html">内置工具目录</a></td></tr><tr><td><code>list_sessions()</code></td><td>🟠</td><td>列举跨进程历史会话（返回形态已定,签名已定）</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html#list-sessions">会话管理</a></td></tr><tr><td><code>get_session_messages(session_id)</code></td><td>🟠</td><td>取某会话的消息（返回 <code>TranscriptMessage</code> 列表,形态已定）</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html#get-session-messages">会话管理</a></td></tr><tr><td><code>get_session_info(session_id)</code></td><td>🟠</td><td>取某会话的元信息（返回 <code>SessionInfo</code>,形态已定）</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html#get-session-info">会话管理</a></td></tr><tr><td><code>rename_session(session_id, title)</code></td><td>🟠</td><td>重命名会话（签名已定）</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html#rename-session">会话管理</a></td></tr><tr><td><code>tag_session(session_id, tag)</code></td><td>⚪</td><td>打标签,暂缓</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html">会话管理</a></td></tr></tbody></table><h2 id="classes" tabindex="-1">Classes <a class="header-anchor" href="#classes" aria-label="Permalink to &quot;Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>接口</th><th>状态</th><th>一句话</th><th>去哪页</th></tr></thead><tbody><tr><td><code>BrainaryClient</code></td><td>🟠</td><td>有状态多轮客户端；<code>async with</code> + <code>query</code> / <code>receive_response</code> / <code>await interrupt()</code> 及只读检视方法</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/query-and-client.html#brainaryclient-只读检视与单步">两个入口</a></td></tr></tbody></table><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>接口</th><th>状态</th><th>一句话</th><th>去哪页</th></tr></thead><tbody><tr><td><code>Options</code>（dataclass)</td><td>🟠</td><td>唯一配置对象,所有行为收敛于此</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/options.html#字段逐项">Options</a></td></tr><tr><td><code>ModelSelection</code></td><td>🟠</td><td>模型接入信息（<code>Options.model_from_env()</code> / 显式构造)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/options.html">Options</a></td></tr><tr><td><code>SystemPrompt</code></td><td>🟠</td><td>系统提示三来源（Default / Inline / TemplateFile)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/options.html#系统提示-systemprompt">Options</a></td></tr><tr><td><code>Message</code>（union)</td><td>🟠</td><td>流的元素,用 <code>isinstance</code> 判型</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#四类消息">消息模型</a></td></tr><tr><td><code>AssistantMessage</code> / <code>UserMessage</code> / <code>SystemMessage</code> / <code>ResultMessage</code></td><td>🟠</td><td>四类消息（<code>UserMessage</code> 待上游填充)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#四类消息">消息模型</a></td></tr><tr><td><code>ContentBlock</code>（union)</td><td>🟠</td><td>内容块：<code>TextBlock</code>(🟠) / <code>ToolUseBlock</code> / <code>ToolResultBlock</code> / <code>ThinkingBlock</code>(🟠 类型就位不填充)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#content-block">消息模型</a></td></tr><tr><td><code>stop_reason</code>（4 取值)</td><td>🟠</td><td>终局原因（stopped / max_turns / interrupted / context_exhausted)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#stopreason">消息模型</a></td></tr><tr><td><code>Usage</code> / <code>ResultMessage.total_cost_usd</code></td><td>🟠</td><td>成本面,类型就位、值恒 <code>None</code> 待上游</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html#cost">成本</a></td></tr><tr><td><code>SdkMcpTool</code> / <code>CapabilityUnit</code></td><td>🟠</td><td><code>@tool</code> 产物 / <code>create_sdk_mcp_server()</code> 产物</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/tools.html">自定义工具</a></td></tr><tr><td><code>SessionTranscript</code> / <code>TranscriptMessage</code></td><td>🟠</td><td>只读会话快照（<code>export_transcript()</code>,不可续跑)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/query-and-client.html#brainaryclient-只读检视与单步">两个入口</a></td></tr><tr><td><code>SessionInfo</code> / <code>SessionMessage</code></td><td>🟠</td><td>会话元信息 / 会话消息（形态已定)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/sessions.html#返回类型-sessioninfo-完整字段集">会话管理</a></td></tr><tr><td><code>PermissionMode</code>（6 模） / <code>CanUseTool</code> / <code>ToolPermissionContext</code> / <code>PermissionResultAllow</code> / <code>PermissionResultDeny</code> / <code>PermissionUpdate</code> / <code>PermissionRuleValue</code></td><td>🟠</td><td>权限控制面全套：模式枚举（default / acceptEdits / bypassPermissions / plan / … 6 态）、回调、上下文、允/拒判定结果、运行时增量更新与规则值</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a></td></tr><tr><td><code>allowed_tools</code> / <code>disallowed_tools</code></td><td>🟠</td><td>工具准入白/黑名单（<code>Options</code> 字段,与权限判定联动)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/permissions.html">权限模型</a></td></tr><tr><td><code>agents</code> / <code>AgentDefinition</code></td><td>🟠</td><td>SDK 直挂子代理（在 <code>Options</code> 内声明式定义）</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/options.html">Options</a> · 子代理</td></tr><tr><td><code>setting_sources</code> / <code>add_dirs</code> / <code>sandbox</code> / <code>plugins</code> / <code>output_format</code> / <code>thinking</code> / <code>effort</code> / <code>fallback_model</code></td><td>🟠</td><td><code>Options</code> 配置旋钮：设置来源、附加工作目录、沙箱、插件、输出格式、思考开关、努力档位、回退模型</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/options.html">Options</a></td></tr><tr><td><code>HookEvent</code> / <code>HookMatcher</code> / <code>HookCallback</code> / <code>HookInput</code> / <code>HookJSONOutput</code></td><td>🟠</td><td>Hooks 子系统五件套：事件枚举、匹配器、回调、输入、结构化输出</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/hooks.html">Hooks</a></td></tr><tr><td><code>AssistantMessageError</code></td><td>🟠</td><td>助手消息内的错误块（类型就位）</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html">消息模型</a></td></tr><tr><td><code>RateLimitEvent</code> / <code>RateLimitInfo</code></td><td>🟠</td><td>限流事件与配额信息（形态已定,未透出）</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/messages.html">消息模型</a></td></tr><tr><td><code>ToolAnnotations</code></td><td>🟠</td><td>工具行为提示（占位)</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/tools.html#toolannotations-工具行为提示-架构占位">自定义工具</a></td></tr><tr><td><code>McpServerConfig</code> 家族（Stdio / SSE / Http + 鉴权 <code>headers</code>）</td><td>🟠</td><td>MCP server 富配置：三种传输 + 鉴权头（糖仍可只收 URL）</td><td>MCP 接入</td></tr><tr><td><code>BrainaryError</code> 异常类树（<code>BuildError</code> / <code>AuthenticationError</code> / <code>RateLimitError</code> / <code>ToolExecutionError</code> …）</td><td>🟠</td><td>自解释命名的异常子类,<code>except 具体子类</code> 分支;<code>except BrainaryError</code> 兜底。不设 <code>CLI*Error</code> 一族</td><td><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/errors.html">错误处理</a></td></tr></tbody></table><blockquote><p>上表已登记本轮新增的内置工具、Hooks、权限全套、<code>Options</code> 旋钮与消息新增类型。其余全表面（含 <code>Transport</code> / <code>StreamEvent</code> / 后台任务消息等尚未落地的接口)的<strong>处置决策</strong>见 <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/limits.html#coverage-matrix">边界与路线图 · 覆盖矩阵</a>。</p></blockquote><h2 id="相关" tabindex="-1">相关 <a class="header-anchor" href="#相关" aria-label="Permalink to &quot;相关&quot;">​</a></h2><ul><li><a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/overview.html">能力总览</a> · <a href="/brainary-agent-sdk-docs/docs/3caa334/sdk-py/limits.html">边界与路线图</a></li><li>对照 Rust 版：<a href="/brainary-agent-sdk-docs/docs/3caa334/sdk/api-index.html">接口索引</a></li></ul>',15)])])}const k=d(a,[["render",c]]);export{y as __pageData,k as default};
